import json
import os

base = "C:/Users/Peter/pkang6689-pixel.github.io/content_data/PrecalculusLessons"

def update_quiz(filepath, new_questions):
    with open(filepath, 'r', encoding='utf-8') as f:
        data = json.load(f)
    if len(data['quiz_questions']) >= 30:
        print(f"SKIP {os.path.basename(filepath)}: already {len(data['quiz_questions'])} questions")
        return
    data['quiz_questions'].extend(new_questions)
    with open(filepath, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
    print(f"OK {os.path.basename(filepath)}: now {len(data['quiz_questions'])} questions")

# ============================================================
# LESSON 2.1: Linear Equations & Graphs
# ============================================================
update_quiz(f"{base}/Unit2/Lesson2.1_Quiz.json", [
    {"question_number": 21, "question_text": "A plumber charges a $50 service fee plus $30 per hour. If the total bill is $200, how many hours did the job take?", "attempted": 2, "data_i18n": None, "options": [{"text": "4 hours", "is_correct": False, "data_i18n": None}, {"text": "5 hours", "is_correct": True, "data_i18n": None}, {"text": "6 hours", "is_correct": False, "data_i18n": None}, {"text": "7 hours", "is_correct": False, "data_i18n": None}], "explanation": "50 + 30h = 200, so 30h = 150, giving h = 5 hours."},
    {"question_number": 22, "question_text": "A phone plan costs $25/month plus $0.10 per text. If a student sends 300 texts, what is the monthly bill?", "attempted": 2, "data_i18n": None, "options": [{"text": "$55", "is_correct": True, "data_i18n": None}, {"text": "$50", "is_correct": False, "data_i18n": None}, {"text": "$75", "is_correct": False, "data_i18n": None}, {"text": "$325", "is_correct": False, "data_i18n": None}], "explanation": "C = 25 + 0.10(300) = 25 + 30 = $55."},
    {"question_number": 23, "question_text": "A car's value depreciates linearly from $20,000 to $8,000 over 6 years. What is the annual depreciation rate?", "attempted": 2, "data_i18n": None, "options": [{"text": "$1,500/year", "is_correct": False, "data_i18n": None}, {"text": "$2,000/year", "is_correct": True, "data_i18n": None}, {"text": "$2,500/year", "is_correct": False, "data_i18n": None}, {"text": "$3,000/year", "is_correct": False, "data_i18n": None}], "explanation": "Depreciation = (20000 - 8000)/6 = 12000/6 = $2,000 per year."},
    {"question_number": 24, "question_text": "A bakery sells cupcakes for $3 each. Fixed daily costs are $60. How many cupcakes must be sold to earn $150 in revenue?", "attempted": 2, "data_i18n": None, "options": [{"text": "50", "is_correct": True, "data_i18n": None}, {"text": "70", "is_correct": False, "data_i18n": None}, {"text": "40", "is_correct": False, "data_i18n": None}, {"text": "60", "is_correct": False, "data_i18n": None}], "explanation": "Revenue = 3x = 150, so x = 50 cupcakes."},
    {"question_number": 25, "question_text": "A pool is being filled at a constant rate. It has 50 gallons at t = 0 and 200 gallons at t = 5 hours. What is the linear equation?", "attempted": 2, "data_i18n": None, "options": [{"text": "V = 30t + 50", "is_correct": True, "data_i18n": None}, {"text": "V = 50t + 30", "is_correct": False, "data_i18n": None}, {"text": "V = 40t + 50", "is_correct": False, "data_i18n": None}, {"text": "V = 25t + 50", "is_correct": False, "data_i18n": None}], "explanation": "Rate = (200-50)/5 = 30 gal/hr. Starting at 50: V = 30t + 50."},
    {"question_number": 26, "question_text": "Two cities are 300 miles apart. A truck travels at 50 mph. Distance remaining: d = 300 \u2212 50t. When does the truck arrive?", "attempted": 2, "data_i18n": None, "options": [{"text": "5 hours", "is_correct": False, "data_i18n": None}, {"text": "6 hours", "is_correct": True, "data_i18n": None}, {"text": "7 hours", "is_correct": False, "data_i18n": None}, {"text": "4 hours", "is_correct": False, "data_i18n": None}], "explanation": "Set d = 0: 300 \u2212 50t = 0, so t = 6 hours."},
    {"question_number": 27, "question_text": "A gym membership is $40/month. A competing gym charges $100 sign-up + $25/month. After how many months do they cost the same?", "attempted": 2, "data_i18n": None, "options": [{"text": "About 7 months", "is_correct": True, "data_i18n": None}, {"text": "About 5 months", "is_correct": False, "data_i18n": None}, {"text": "About 10 months", "is_correct": False, "data_i18n": None}, {"text": "About 4 months", "is_correct": False, "data_i18n": None}], "explanation": "40m = 100 + 25m gives 15m = 100, so m = 6.67, about 7 months."},
    {"question_number": 28, "question_text": "A candle is 12 inches tall and burns at 0.5 inches per hour. After how many hours will it be 3 inches tall?", "attempted": 2, "data_i18n": None, "options": [{"text": "16 hours", "is_correct": False, "data_i18n": None}, {"text": "18 hours", "is_correct": True, "data_i18n": None}, {"text": "20 hours", "is_correct": False, "data_i18n": None}, {"text": "15 hours", "is_correct": False, "data_i18n": None}], "explanation": "h = 12 \u2212 0.5t. Set h = 3: 12 \u2212 0.5t = 3, so 0.5t = 9, t = 18 hours."},
    {"question_number": 29, "question_text": "A salesperson earns $500/week plus $20 per sale. She needs $900 this week. How many sales are required?", "attempted": 2, "data_i18n": None, "options": [{"text": "15", "is_correct": False, "data_i18n": None}, {"text": "20", "is_correct": True, "data_i18n": None}, {"text": "25", "is_correct": False, "data_i18n": None}, {"text": "10", "is_correct": False, "data_i18n": None}], "explanation": "500 + 20s = 900, so 20s = 400, s = 20 sales."},
    {"question_number": 30, "question_text": "A spring stretches linearly: 2 cm per Newton of force, starting at 10 cm. At 7 Newtons, the length is:", "attempted": 2, "data_i18n": None, "options": [{"text": "22 cm", "is_correct": False, "data_i18n": None}, {"text": "24 cm", "is_correct": True, "data_i18n": None}, {"text": "17 cm", "is_correct": False, "data_i18n": None}, {"text": "20 cm", "is_correct": False, "data_i18n": None}], "explanation": "L = 10 + 2F = 10 + 2(7) = 10 + 14 = 24 cm."}
])

# ============================================================
# LESSON 2.2: Slope, Intercepts, and Parallel/Perpendicular Lines
# ============================================================
update_quiz(f"{base}/Unit2/Lesson2.2_Quiz.json", [
    {"question_number": 21, "question_text": "A road rises 150 feet over a horizontal distance of 3,000 feet. What is the grade (slope) of the road?", "attempted": 2, "data_i18n": None, "options": [{"text": "5%", "is_correct": True, "data_i18n": None}, {"text": "10%", "is_correct": False, "data_i18n": None}, {"text": "3%", "is_correct": False, "data_i18n": None}, {"text": "15%", "is_correct": False, "data_i18n": None}], "explanation": "Slope = rise/run = 150/3000 = 0.05 = 5%."},
    {"question_number": 22, "question_text": "A wheelchair ramp must have a slope no steeper than 1/12. If the ramp rises 2 feet, what is the minimum horizontal length?", "attempted": 2, "data_i18n": None, "options": [{"text": "20 feet", "is_correct": False, "data_i18n": None}, {"text": "24 feet", "is_correct": True, "data_i18n": None}, {"text": "12 feet", "is_correct": False, "data_i18n": None}, {"text": "30 feet", "is_correct": False, "data_i18n": None}], "explanation": "Slope = 2/x = 1/12, so x = 24 feet minimum."},
    {"question_number": 23, "question_text": "Two streets are parallel with slopes of 3/4. A new street must be perpendicular to them. What is its slope?", "attempted": 2, "data_i18n": None, "options": [{"text": "3/4", "is_correct": False, "data_i18n": None}, {"text": "\u22124/3", "is_correct": True, "data_i18n": None}, {"text": "4/3", "is_correct": False, "data_i18n": None}, {"text": "\u22123/4", "is_correct": False, "data_i18n": None}], "explanation": "Perpendicular slope is the negative reciprocal: \u22124/3."},
    {"question_number": 24, "question_text": "A cable car rises from elevation 2,000 ft to 3,500 ft over a horizontal distance of 6,000 ft. What is the slope?", "attempted": 2, "data_i18n": None, "options": [{"text": "1/4", "is_correct": True, "data_i18n": None}, {"text": "1/3", "is_correct": False, "data_i18n": None}, {"text": "3/4", "is_correct": False, "data_i18n": None}, {"text": "1/2", "is_correct": False, "data_i18n": None}], "explanation": "Slope = (3500 \u2212 2000)/6000 = 1500/6000 = 1/4."},
    {"question_number": 25, "question_text": "An architect designs a roof with slope 5/12. A drain pipe must run perpendicular to the roof line. What is the pipe's slope?", "attempted": 2, "data_i18n": None, "options": [{"text": "\u221212/5", "is_correct": True, "data_i18n": None}, {"text": "12/5", "is_correct": False, "data_i18n": None}, {"text": "\u22125/12", "is_correct": False, "data_i18n": None}, {"text": "5/12", "is_correct": False, "data_i18n": None}], "explanation": "Perpendicular slope = negative reciprocal of 5/12 = \u221212/5."},
    {"question_number": 26, "question_text": "A stock price was $40 on day 1 and $55 on day 31. What is the average rate of change per day?", "attempted": 2, "data_i18n": None, "options": [{"text": "$0.50/day", "is_correct": True, "data_i18n": None}, {"text": "$0.75/day", "is_correct": False, "data_i18n": None}, {"text": "$1.00/day", "is_correct": False, "data_i18n": None}, {"text": "$1.50/day", "is_correct": False, "data_i18n": None}], "explanation": "Rate = (55 \u2212 40)/(31 \u2212 1) = 15/30 = $0.50 per day."},
    {"question_number": 27, "question_text": "Train track A has equation y = 2x + 5. Track B runs parallel through point (3, 1). What is Track B's equation?", "attempted": 2, "data_i18n": None, "options": [{"text": "y = 2x \u2212 5", "is_correct": True, "data_i18n": None}, {"text": "y = 2x + 1", "is_correct": False, "data_i18n": None}, {"text": "y = \u2212(1/2)x + 5", "is_correct": False, "data_i18n": None}, {"text": "y = 2x \u2212 3", "is_correct": False, "data_i18n": None}], "explanation": "Parallel means same slope m = 2. Using point (3,1): 1 = 2(3) + b, b = \u22125. So y = 2x \u2212 5."},
    {"question_number": 28, "question_text": "A hiking trail drops 400 feet in elevation over 2 miles (10,560 ft). What is the trail's slope?", "attempted": 2, "data_i18n": None, "options": [{"text": "\u22121/26.4", "is_correct": True, "data_i18n": None}, {"text": "\u22121/5", "is_correct": False, "data_i18n": None}, {"text": "400/2", "is_correct": False, "data_i18n": None}, {"text": "\u22121/10", "is_correct": False, "data_i18n": None}], "explanation": "Slope = \u2212400/10560 = \u22121/26.4 (negative because it drops)."},
    {"question_number": 29, "question_text": "A water pipe runs along y = \u22123x + 10. A new pipe must cross it at a right angle at x = 2. What is the new pipe's equation?", "attempted": 2, "data_i18n": None, "options": [{"text": "y = (1/3)x + 10/3", "is_correct": True, "data_i18n": None}, {"text": "y = 3x \u2212 2", "is_correct": False, "data_i18n": None}, {"text": "y = (1/3)x + 4", "is_correct": False, "data_i18n": None}, {"text": "y = \u2212(1/3)x + 2", "is_correct": False, "data_i18n": None}], "explanation": "At x=2: y = \u22126+10 = 4. Perpendicular slope = 1/3. y \u2212 4 = (1/3)(x \u2212 2), so y = (1/3)x + 10/3."},
    {"question_number": 30, "question_text": "A conveyor belt moves items on a line y = (2/5)x + 3. A sorting chute must be perpendicular. What slope does the chute have?", "attempted": 2, "data_i18n": None, "options": [{"text": "\u22125/2", "is_correct": True, "data_i18n": None}, {"text": "5/2", "is_correct": False, "data_i18n": None}, {"text": "2/5", "is_correct": False, "data_i18n": None}, {"text": "\u22122/5", "is_correct": False, "data_i18n": None}], "explanation": "Perpendicular slope = negative reciprocal of 2/5 = \u22125/2."}
])

