# LESSON 2.3: Quadratic Functions (vertex form, standard form)
# ============================================================
update_quiz(f"{base}/Unit2/Lesson2.3_Quiz.json", [
    {"question_number": 21, "question_text": "A ball is thrown upward with h(t) = \u221216t\u00b2 + 96t + 5. What is the maximum height?", "attempted": 2, "data_i18n": None, "options": [{"text": "149 feet", "is_correct": True, "data_i18n": None}, {"text": "96 feet", "is_correct": False, "data_i18n": None}, {"text": "144 feet", "is_correct": False, "data_i18n": None}, {"text": "160 feet", "is_correct": False, "data_i18n": None}], "explanation": "Vertex at t = \u221296/(2(\u221216)) = 3. h(3) = \u221216(9) + 96(3) + 5 = \u2212144 + 288 + 5 = 149 feet."},
    {"question_number": 22, "question_text": "A company's profit is P(x) = \u22122(x \u2212 50)\u00b2 + 5000. What price x maximizes profit and what is the maximum?", "attempted": 2, "data_i18n": None, "options": [{"text": "x = 50, max profit = $5,000", "is_correct": True, "data_i18n": None}, {"text": "x = 50, max profit = $2,500", "is_correct": False, "data_i18n": None}, {"text": "x = 25, max profit = $5,000", "is_correct": False, "data_i18n": None}, {"text": "x = 100, max profit = $5,000", "is_correct": False, "data_i18n": None}], "explanation": "In vertex form \u22122(x\u221250)\u00b2+5000, the vertex is (50, 5000). Max profit is $5,000 at x = 50."},
    {"question_number": 23, "question_text": "A farmer wants to maximize a rectangular pen with 100 m of fencing. The area is A(w) = w(50 \u2212 w). What is the maximum area?", "attempted": 2, "data_i18n": None, "options": [{"text": "500 m\u00b2", "is_correct": False, "data_i18n": None}, {"text": "625 m\u00b2", "is_correct": True, "data_i18n": None}, {"text": "2500 m\u00b2", "is_correct": False, "data_i18n": None}, {"text": "100 m\u00b2", "is_correct": False, "data_i18n": None}], "explanation": "A = 50w \u2212 w\u00b2 = \u2212(w\u221225)\u00b2 + 625. Maximum area is 625 m\u00b2 at w = 25 m."},
    {"question_number": 24, "question_text": "A bridge arch is modeled by y = \u22120.01(x \u2212 100)\u00b2 + 100. What is the maximum height of the arch?", "attempted": 2, "data_i18n": None, "options": [{"text": "50 feet", "is_correct": False, "data_i18n": None}, {"text": "100 feet", "is_correct": True, "data_i18n": None}, {"text": "200 feet", "is_correct": False, "data_i18n": None}, {"text": "10 feet", "is_correct": False, "data_i18n": None}], "explanation": "Vertex form shows the vertex at (100, 100). Maximum height is 100 feet."},
    {"question_number": 25, "question_text": "A stadium ticket price and attendance: R(p) = \u221250p\u00b2 + 2000p. What ticket price maximizes revenue?", "attempted": 2, "data_i18n": None, "options": [{"text": "$20", "is_correct": True, "data_i18n": None}, {"text": "$40", "is_correct": False, "data_i18n": None}, {"text": "$50", "is_correct": False, "data_i18n": None}, {"text": "$10", "is_correct": False, "data_i18n": None}], "explanation": "Vertex at p = \u22122000/(2(\u221250)) = 2000/100 = $20."},
    {"question_number": 26, "question_text": "A toy rocket h(t) = \u22124.9t\u00b2 + 29.4t launches from the ground. When does it return to the ground?", "attempted": 2, "data_i18n": None, "options": [{"text": "3 seconds", "is_correct": False, "data_i18n": None}, {"text": "6 seconds", "is_correct": True, "data_i18n": None}, {"text": "4.9 seconds", "is_correct": False, "data_i18n": None}, {"text": "10 seconds", "is_correct": False, "data_i18n": None}], "explanation": "Set h = 0: t(\u22124.9t + 29.4) = 0. So t = 0 or t = 29.4/4.9 = 6 seconds."},
    {"question_number": 27, "question_text": "An investor's returns are modeled by R(x) = \u2212x\u00b2 + 12x \u2212 20. Convert to vertex form to find maximum return.", "attempted": 2, "data_i18n": None, "options": [{"text": "\u2212(x \u2212 6)\u00b2 + 16, max = 16", "is_correct": True, "data_i18n": None}, {"text": "\u2212(x \u2212 12)\u00b2 + 20, max = 20", "is_correct": False, "data_i18n": None}, {"text": "\u2212(x \u2212 6)\u00b2 + 20, max = 20", "is_correct": False, "data_i18n": None}, {"text": "\u2212(x \u2212 3)\u00b2 + 16, max = 16", "is_correct": False, "data_i18n": None}], "explanation": "\u2212(x\u00b2 \u2212 12x) \u2212 20 = \u2212(x\u00b2 \u2212 12x + 36) + 36 \u2212 20 = \u2212(x\u22126)\u00b2 + 16. Max is 16 at x = 6."},
    {"question_number": 28, "question_text": "A diver's height above water: h(t) = \u22125t\u00b2 + 10t + 3 meters. What is the diver's maximum height?", "attempted": 2, "data_i18n": None, "options": [{"text": "8 meters", "is_correct": True, "data_i18n": None}, {"text": "10 meters", "is_correct": False, "data_i18n": None}, {"text": "5 meters", "is_correct": False, "data_i18n": None}, {"text": "3 meters", "is_correct": False, "data_i18n": None}], "explanation": "Vertex at t = \u221210/(2(\u22125)) = 1. h(1) = \u22125 + 10 + 3 = 8 meters."},
    {"question_number": 29, "question_text": "A catapult launches a stone: h(x) = \u2212(1/100)x\u00b2 + 2x, where x is horizontal distance. How far does the stone travel?", "attempted": 2, "data_i18n": None, "options": [{"text": "100 feet", "is_correct": False, "data_i18n": None}, {"text": "200 feet", "is_correct": True, "data_i18n": None}, {"text": "150 feet", "is_correct": False, "data_i18n": None}, {"text": "50 feet", "is_correct": False, "data_i18n": None}], "explanation": "Set h = 0: x(\u2212x/100 + 2) = 0. So x = 0 or x = 200 feet."},
    {"question_number": 30, "question_text": "A parabolic antenna is described by y = (1/8)x\u00b2 \u2212 2x + 10. What is the vertex (lowest point)?", "attempted": 2, "data_i18n": None, "options": [{"text": "(8, 2)", "is_correct": True, "data_i18n": None}, {"text": "(4, 4)", "is_correct": False, "data_i18n": None}, {"text": "(2, 8)", "is_correct": False, "data_i18n": None}, {"text": "(10, 0)", "is_correct": False, "data_i18n": None}], "explanation": "x = \u2212(\u22122)/(2(1/8)) = 2/(1/4) = 8. y = (1/8)(64) \u2212 16 + 10 = 8 \u2212 16 + 10 = 2. Vertex: (8, 2)."}
])

