# LESSON 2.4: Completing the Square
# ============================================================
update_quiz(f"{base}/Unit2/Lesson2.4_Quiz.json", [
    {"question_number": 21, "question_text": "A landscaper models a garden's area as A = \u2212x\u00b2 + 14x. Complete the square to find the maximum area.", "attempted": 2, "data_i18n": None, "options": [{"text": "49 sq units", "is_correct": True, "data_i18n": None}, {"text": "14 sq units", "is_correct": False, "data_i18n": None}, {"text": "196 sq units", "is_correct": False, "data_i18n": None}, {"text": "7 sq units", "is_correct": False, "data_i18n": None}], "explanation": "\u2212(x\u00b2 \u2212 14x) = \u2212(x\u00b2 \u2212 14x + 49) + 49 = \u2212(x \u2212 7)\u00b2 + 49. Max area is 49."},
    {"question_number": 22, "question_text": "A ball's height is h = \u221216t\u00b2 + 64t + 10. Complete the square to find maximum height.", "attempted": 2, "data_i18n": None, "options": [{"text": "74 feet", "is_correct": True, "data_i18n": None}, {"text": "64 feet", "is_correct": False, "data_i18n": None}, {"text": "10 feet", "is_correct": False, "data_i18n": None}, {"text": "80 feet", "is_correct": False, "data_i18n": None}], "explanation": "\u221216(t\u00b2 \u2212 4t) + 10 = \u221216(t\u00b2 \u2212 4t + 4) + 64 + 10 = \u221216(t\u22122)\u00b2 + 74. Max: 74 feet."},
    {"question_number": 23, "question_text": "A business models profit as P(x) = \u22123x\u00b2 + 36x \u2212 50. Use completing the square to find the maximum profit.", "attempted": 2, "data_i18n": None, "options": [{"text": "$58", "is_correct": True, "data_i18n": None}, {"text": "$36", "is_correct": False, "data_i18n": None}, {"text": "$108", "is_correct": False, "data_i18n": None}, {"text": "$50", "is_correct": False, "data_i18n": None}], "explanation": "\u22123(x\u00b2 \u2212 12x) \u2212 50 = \u22123(x\u00b2 \u2212 12x + 36) + 108 \u2212 50 = \u22123(x\u22126)\u00b2 + 58. Max: $58."},
    {"question_number": 24, "question_text": "A circular sprinkler waters an area modeled by x\u00b2 + y\u00b2 + 6x \u2212 4y = 12. Complete the square to find the radius.", "attempted": 2, "data_i18n": None, "options": [{"text": "5", "is_correct": True, "data_i18n": None}, {"text": "25", "is_correct": False, "data_i18n": None}, {"text": "12", "is_correct": False, "data_i18n": None}, {"text": "3", "is_correct": False, "data_i18n": None}], "explanation": "(x\u00b2+6x+9) + (y\u00b2\u22124y+4) = 12+9+4 = 25. So (x+3)\u00b2 + (y\u22122)\u00b2 = 25, radius = 5."},
    {"question_number": 25, "question_text": "An engineer models a cable as y = 2x\u00b2 \u2212 8x + 15. Complete the square to find the lowest point.", "attempted": 2, "data_i18n": None, "options": [{"text": "(2, 7)", "is_correct": True, "data_i18n": None}, {"text": "(4, 15)", "is_correct": False, "data_i18n": None}, {"text": "(2, 15)", "is_correct": False, "data_i18n": None}, {"text": "(8, 7)", "is_correct": False, "data_i18n": None}], "explanation": "2(x\u00b2\u22124x) + 15 = 2(x\u00b2\u22124x+4) \u2212 8 + 15 = 2(x\u22122)\u00b2 + 7. Vertex: (2, 7)."},
    {"question_number": 26, "question_text": "A diver's path is y = \u2212x\u00b2 + 6x + 5. Complete the square to find the peak height.", "attempted": 2, "data_i18n": None, "options": [{"text": "14", "is_correct": True, "data_i18n": None}, {"text": "9", "is_correct": False, "data_i18n": None}, {"text": "11", "is_correct": False, "data_i18n": None}, {"text": "5", "is_correct": False, "data_i18n": None}], "explanation": "\u2212(x\u00b2\u22126x)+5 = \u2212(x\u00b2\u22126x+9)+9+5 = \u2212(x\u22123)\u00b2+14. Peak: 14."},
    {"question_number": 27, "question_text": "A river cross-section is modeled by d = x\u00b2 + 10x + 30 (depth in feet). What is the minimum depth?", "attempted": 2, "data_i18n": None, "options": [{"text": "5 feet", "is_correct": True, "data_i18n": None}, {"text": "30 feet", "is_correct": False, "data_i18n": None}, {"text": "10 feet", "is_correct": False, "data_i18n": None}, {"text": "25 feet", "is_correct": False, "data_i18n": None}], "explanation": "(x\u00b2+10x+25)+30\u221225 = (x+5)\u00b2+5. Minimum depth: 5 feet at x = \u22125."},
    {"question_number": 28, "question_text": "A factory's energy cost is C(t) = 4t\u00b2 \u2212 24t + 100 dollars. At what hour t is cost minimized?", "attempted": 2, "data_i18n": None, "options": [{"text": "t = 3", "is_correct": True, "data_i18n": None}, {"text": "t = 6", "is_correct": False, "data_i18n": None}, {"text": "t = 12", "is_correct": False, "data_i18n": None}, {"text": "t = 24", "is_correct": False, "data_i18n": None}], "explanation": "4(t\u00b2\u22126t)+100 = 4(t\u22123)\u00b2\u221236+100 = 4(t\u22123)\u00b2+64. Minimum at t = 3."},
    {"question_number": 29, "question_text": "A projectile travels h = \u22125t\u00b2 + 30t + 2. Complete the square to find when it reaches max height.", "attempted": 2, "data_i18n": None, "options": [{"text": "t = 3 seconds", "is_correct": True, "data_i18n": None}, {"text": "t = 6 seconds", "is_correct": False, "data_i18n": None}, {"text": "t = 5 seconds", "is_correct": False, "data_i18n": None}, {"text": "t = 2 seconds", "is_correct": False, "data_i18n": None}], "explanation": "\u22125(t\u00b2\u22126t)+2 = \u22125(t\u22123)\u00b2+45+2 = \u22125(t\u22123)\u00b2+47. Max at t = 3 seconds."},
    {"question_number": 30, "question_text": "A parabolic mirror is y = 3x\u00b2 \u2212 12x + 20. By completing the square, find the focal depth (vertex y-value).", "attempted": 2, "data_i18n": None, "options": [{"text": "8", "is_correct": True, "data_i18n": None}, {"text": "20", "is_correct": False, "data_i18n": None}, {"text": "12", "is_correct": False, "data_i18n": None}, {"text": "4", "is_correct": False, "data_i18n": None}], "explanation": "3(x\u00b2\u22124x)+20 = 3(x\u22122)\u00b2\u221212+20 = 3(x\u22122)\u00b2+8. Vertex at (2, 8)."}
])

