update_quiz(f"{base}/Unit2/Lesson2.5_Quiz.json", [
    {"question_number": 21, "question_text": "An electronics company models profit: P(x) = \u22122x\u00b2 + 28x \u2212 90. At what quantities does the company break even?", "attempted": 2, "data_i18n": None, "options": [{"text": "x = 5 and x = 9", "is_correct": True, "data_i18n": None}, {"text": "x = 7 and x = 14", "is_correct": False, "data_i18n": None}, {"text": "x = 3 and x = 15", "is_correct": False, "data_i18n": None}, {"text": "x = 4 and x = 10", "is_correct": False, "data_i18n": None}], "explanation": "Set P = 0: \u22122x\u00b2+28x\u221290=0, so x\u00b2\u221214x+45=0. x = (14\u00b1\u221a(196\u2212180))/2 = (14\u00b14)/2. x = 5 or x = 9."},
    {"question_number": 22, "question_text": "A missile follows h = \u22124.9t\u00b2 + 20t + 50. Using the quadratic formula, when does it hit the ground?", "attempted": 2, "data_i18n": None, "options": [{"text": "About 5.8 seconds", "is_correct": True, "data_i18n": None}, {"text": "About 4.1 seconds", "is_correct": False, "data_i18n": None}, {"text": "About 10.2 seconds", "is_correct": False, "data_i18n": None}, {"text": "About 3.0 seconds", "is_correct": False, "data_i18n": None}], "explanation": "\u22124.9t\u00b2+20t+50=0. t = (\u221220\u00b1\u221a(400+980))/(\u22129.8) = (\u221220\u00b1\u221a1380)/(\u22129.8). Positive root: about 5.8 seconds."},
    {"question_number": 23, "question_text": "A circuit has impedance equation x\u00b2 + 4x + 13 = 0. What is the discriminant and what does it tell us?", "attempted": 2, "data_i18n": None, "options": [{"text": "\u221236; two complex solutions (no real roots)", "is_correct": True, "data_i18n": None}, {"text": "36; two real solutions", "is_correct": False, "data_i18n": None}, {"text": "0; one real solution", "is_correct": False, "data_i18n": None}, {"text": "4; two real solutions", "is_correct": False, "data_i18n": None}], "explanation": "Discriminant = 16 \u2212 52 = \u221236. Since it is negative, there are two complex (non-real) solutions."},
    {"question_number": 24, "question_text": "A ball is thrown from a cliff: h = \u221216t\u00b2 + 32t + 80. The discriminant of h = 0 is:", "attempted": 2, "data_i18n": None, "options": [{"text": "6144", "is_correct": True, "data_i18n": None}, {"text": "\u22126144", "is_correct": False, "data_i18n": None}, {"text": "1024", "is_correct": False, "data_i18n": None}, {"text": "0", "is_correct": False, "data_i18n": None}], "explanation": "D = 32\u00b2 \u2212 4(\u221216)(80) = 1024 + 5120 = 6144. Positive, so two real times (ball reaches ground)."},
    {"question_number": 25, "question_text": "A building's profit per unit is modeled by 3x\u00b2 \u2212 10x + 15 = 0. Can this equation have real solutions?", "attempted": 2, "data_i18n": None, "options": [{"text": "Yes, two real solutions", "is_correct": False, "data_i18n": None}, {"text": "No, discriminant is \u221280", "is_correct": True, "data_i18n": None}, {"text": "Yes, one real solution", "is_correct": False, "data_i18n": None}, {"text": "No, discriminant is 0", "is_correct": False, "data_i18n": None}], "explanation": "D = 100 \u2212 4(3)(15) = 100 \u2212 180 = \u221280. Negative discriminant means no real solutions."},
    {"question_number": 26, "question_text": "A swimmer's path crosses a current modeled by 2x\u00b2 \u2212 12x + 18 = 0. How many times does the swimmer cross?", "attempted": 2, "data_i18n": None, "options": [{"text": "Twice", "is_correct": False, "data_i18n": None}, {"text": "Once (tangent)", "is_correct": True, "data_i18n": None}, {"text": "Never", "is_correct": False, "data_i18n": None}, {"text": "Three times", "is_correct": False, "data_i18n": None}], "explanation": "D = 144 \u2212 144 = 0. A zero discriminant means exactly one solution (tangent point)."},
    {"question_number": 27, "question_text": "An AC circuit equation is x\u00b2 + 9 = 0. What are the complex solutions?", "attempted": 2, "data_i18n": None, "options": [{"text": "x = \u00b13i", "is_correct": True, "data_i18n": None}, {"text": "x = \u00b19i", "is_correct": False, "data_i18n": None}, {"text": "x = \u00b13", "is_correct": False, "data_i18n": None}, {"text": "x = \u00b19", "is_correct": False, "data_i18n": None}], "explanation": "x\u00b2 = \u22129, so x = \u00b1\u221a(\u22129) = \u00b13i."},
    {"question_number": 28, "question_text": "A rocket must reach 500 m: \u22124.9t\u00b2 + 80t = 500. Using the quadratic formula, is this achievable?", "attempted": 2, "data_i18n": None, "options": [{"text": "No, discriminant is negative", "is_correct": False, "data_i18n": None}, {"text": "Yes, at about 14.5 seconds", "is_correct": False, "data_i18n": None}, {"text": "Yes, at about 7.5 seconds", "is_correct": False, "data_i18n": None}, {"text": "No, maximum height is about 327 m", "is_correct": True, "data_i18n": None}], "explanation": "Max height at t=80/9.8\u22488.16s: h\u2248326.5m < 500m. The equation 4.9t\u00b2\u221280t+500=0 has D=6400\u22129800=\u22123400<0. Not achievable."},
    {"question_number": 29, "question_text": "A revenue equation 5x\u00b2 \u2212 60x + 200 = 0 models break-even points. What are the solutions?", "attempted": 2, "data_i18n": None, "options": [{"text": "x = 10 and x = 4", "is_correct": False, "data_i18n": None}, {"text": "x = 4 and x = 10", "is_correct": False, "data_i18n": None}, {"text": "x = (60 \u00b1 \u221a(3600 \u2212 4000))/10; no real solutions", "is_correct": True, "data_i18n": None}, {"text": "x = 6 (repeated)", "is_correct": False, "data_i18n": None}], "explanation": "D = 3600 \u2212 4(5)(200) = 3600 \u2212 4000 = \u2212400. Negative discriminant: no real break-even points."},
    {"question_number": 30, "question_text": "A tennis ball trajectory: h = \u22120.05x\u00b2 + x + 1. Using the quadratic formula, at what distance x does it hit the ground?", "attempted": 2, "data_i18n": None, "options": [{"text": "About 20.99 units", "is_correct": True, "data_i18n": None}, {"text": "About 10 units", "is_correct": False, "data_i18n": None}, {"text": "About 15 units", "is_correct": False, "data_i18n": None}, {"text": "About 25 units", "is_correct": False, "data_i18n": None}], "explanation": "\u22120.05x\u00b2+x+1=0 gives 0.05x\u00b2\u2212x\u22121=0. x=(1\u00b1\u221a(1+0.2))/0.1 = (1\u00b1\u221a1.2)/0.1. Positive root: (1+1.095)/0.1 \u2248 20.95."}
])

