    {"question_number": 21, "question_text": "A firework's path is h(t) = \u221216t\u00b2 + 128t. At what time does it explode at maximum height?", "attempted": 2, "data_i18n": None, "options": [{"text": "4 seconds", "is_correct": True, "data_i18n": None}, {"text": "8 seconds", "is_correct": False, "data_i18n": None}, {"text": "2 seconds", "is_correct": False, "data_i18n": None}, {"text": "16 seconds", "is_correct": False, "data_i18n": None}], "explanation": "Vertex at t = \u2212128/(2(\u221216)) = 128/32 = 4 seconds."},
    {"question_number": 22, "question_text": "A suspension bridge cable follows y = 0.002x\u00b2 \u2212 2x + 600. The cable's lowest point occurs at x = ?", "attempted": 2, "data_i18n": None, "options": [{"text": "500", "is_correct": True, "data_i18n": None}, {"text": "250", "is_correct": False, "data_i18n": None}, {"text": "1000", "is_correct": False, "data_i18n": None}, {"text": "600", "is_correct": False, "data_i18n": None}], "explanation": "x = \u2212(\u22122)/(2(0.002)) = 2/0.004 = 500."},
    {"question_number": 23, "question_text": "A parabolic mirror y = 4x\u00b2 opens upward. After shifting right 3 and up 2, the new vertex is:", "attempted": 2, "data_i18n": None, "options": [{"text": "(3, 2)", "is_correct": True, "data_i18n": None}, {"text": "(\u22123, 2)", "is_correct": False, "data_i18n": None}, {"text": "(3, \u22122)", "is_correct": False, "data_i18n": None}, {"text": "(2, 3)", "is_correct": False, "data_i18n": None}], "explanation": "Original vertex (0,0). Shift right 3 and up 2: new vertex (3, 2)."},
    {"question_number": 24, "question_text": "A profit function opens downward with vertex (10, 500). The axis of symmetry is:", "attempted": 2, "data_i18n": None, "options": [{"text": "x = 10", "is_correct": True, "data_i18n": None}, {"text": "y = 500", "is_correct": False, "data_i18n": None}, {"text": "x = 500", "is_correct": False, "data_i18n": None}, {"text": "y = 10", "is_correct": False, "data_i18n": None}], "explanation": "The axis of symmetry passes through the vertex: x = 10."},
    {"question_number": 25, "question_text": "A fountain arc is y = \u2212(1/4)(x \u2212 6)\u00b2 + 9. What are the x-intercepts where water hits the ground?", "attempted": 2, "data_i18n": None, "options": [{"text": "x = 0 and x = 12", "is_correct": True, "data_i18n": None}, {"text": "x = 3 and x = 9", "is_correct": False, "data_i18n": None}, {"text": "x = 6 only", "is_correct": False, "data_i18n": None}, {"text": "x = \u22126 and x = 6", "is_correct": False, "data_i18n": None}], "explanation": "Set y=0: (x\u22126)\u00b2=36, so x\u22126=\u00b16, giving x=0 and x=12."},
    {"question_number": 26, "question_text": "A stadium's seating follows a parabolic curve y = 0.1x\u00b2 with a > 0. The parabola:", "attempted": 2, "data_i18n": None, "options": [{"text": "Opens upward", "is_correct": True, "data_i18n": None}, {"text": "Opens downward", "is_correct": False, "data_i18n": None}, {"text": "Opens to the right", "is_correct": False, "data_i18n": None}, {"text": "Is a straight line", "is_correct": False, "data_i18n": None}], "explanation": "When a > 0 (here a = 0.1), the parabola opens upward."},
    {"question_number": 27, "question_text": "A ball thrown downward from a building: h = 3t\u00b2 \u2212 12t + 100. The y-intercept (t=0) represents:", "attempted": 2, "data_i18n": None, "options": [{"text": "The initial height of 100 feet", "is_correct": True, "data_i18n": None}, {"text": "The maximum height", "is_correct": False, "data_i18n": None}, {"text": "The time to hit the ground", "is_correct": False, "data_i18n": None}, {"text": "The speed of the ball", "is_correct": False, "data_i18n": None}], "explanation": "At t = 0, h = 100. This is the initial height (building height)."},
    {"question_number": 28, "question_text": "An engineer graphs C(x) = 2(x \u2212 8)\u00b2 + 50. The minimum cost occurs at:", "attempted": 2, "data_i18n": None, "options": [{"text": "8 units, costing $50", "is_correct": True, "data_i18n": None}, {"text": "50 units, costing $8", "is_correct": False, "data_i18n": None}, {"text": "2 units, costing $50", "is_correct": False, "data_i18n": None}, {"text": "8 units, costing $114", "is_correct": False, "data_i18n": None}], "explanation": "Vertex form: minimum at x = 8, C(8) = 2(0) + 50 = $50."},
    {"question_number": 29, "question_text": "A soccer ball follows y = \u22120.02x\u00b2 + 0.8x + 1. How high is the ball when kicked (at x = 0)?", "attempted": 2, "data_i18n": None, "options": [{"text": "0 feet", "is_correct": False, "data_i18n": None}, {"text": "1 foot", "is_correct": True, "data_i18n": None}, {"text": "0.8 feet", "is_correct": False, "data_i18n": None}, {"text": "0.02 feet", "is_correct": False, "data_i18n": None}], "explanation": "At x = 0: y = 0 + 0 + 1 = 1 foot (ball starts 1 foot above ground)."},
